from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    if command_type not in ["build", "search"]:
        raise ValueError(f"Invalid command_type: {command_type}. Must be 'build' or 'search'")

    # Create CLI instance and parser
    cli = LeannCLI()
    parser = cli.create_parser()

    # Parse the arguments
    args = parser.parse_args(args_list)

    # Base configuration common to both commands
    config = {
        "verbose": getattr(args, 'verbose', False),
        "index_path": getattr(args, 'index_path', None),
    }

    # Command-specific configuration
    if command_type == "build":
        build_config = {
            "docs": getattr(args, 'docs', []),
            "model": getattr(args, 'model', None),
            "llm_config": _extract_llm_config(args),
            "embedding_model": getattr(args, 'embedding_model', None),
            "backend": getattr(args, 'backend', None),
            "backend_params": _extract_backend_params(args),
        }
        # Filter out None values
        build_config = {k: v for k, v in build_config.items() if v is not None}
        config.update(build_config)

    elif command_type == "search":
        search_config = {
            "query": getattr(args, 'query', None),
            "top_k": getattr(args, 'top_k', None),
            "metadata_filters": _extract_metadata_filters(args),
            "llm_config": _extract_llm_config(args),
            "backend": getattr(args, 'backend', None),
            "backend_params": _extract_backend_params(args),
            "port": getattr(args, 'port', None),
        }
        # Filter out None values
        search_config = {k: v for k, v in search_config.items() if v is not None}
        config.update(search_config)

    return config


def _extract_llm_config(args) -> Optional[Dict[str, Any]]:
    """Extract LLM configuration from parsed arguments."""
    llm_config = {}

    # Extract LLM type and model
    llm_type = getattr(args, 'llm_type', None)
    llm_model = getattr(args, 'llm_model', None)

    if llm_type:
        llm_config["type"] = llm_type
        if llm_model:
            llm_config["model"] = llm_model

        # Extract additional LLM parameters
        llm_host = getattr(args, 'llm_host', None)
        llm_api_key = getattr(args, 'llm_api_key', None)

        if llm_host:
            llm_config["host"] = llm_host
        if llm_api_key:
            llm_config["api_key"] = llm_api_key

    return llm_config if llm_config else None


def _extract_metadata_filters(args) -> Optional[Dict[str, Any]]:
    """Extract metadata filters from parsed arguments."""
    metadata_filters = getattr(args, 'metadata_filters', None)
    if not metadata_filters:
        return None

    # Parse metadata filters from string format to dictionary
    # Expected format: "field1:value1,field2:value2" or JSON string
    try:
        if metadata_filters.startswith('{'):
            # JSON format
            import json
            return json.loads(metadata_filters)
        else:
            # Simple key-value format
            filters = {}
            for filter_pair in metadata_filters.split(','):
                if ':' in filter_pair:
                    key, value = filter_pair.split(':', 1)
                    filters[key.strip()] = value.strip()
            return filters if filters else None
    except (ValueError, AttributeError):
        return None


def _extract_backend_params(args) -> Optional[Dict[str, Any]]:
    """Extract backend-specific parameters from parsed arguments."""
    backend_params = {}

    # Extract common backend parameters
    backend_host = getattr(args, 'backend_host', None)
    backend_port = getattr(args, 'backend_port', None)
    backend_config = getattr(args, 'backend_config', None)

    if backend_host:
        backend_params["host"] = backend_host
    if backend_port:
        backend_params["port"] = backend_port
    if backend_config:
        try:
            import json
            backend_params.update(json.loads(backend_config))
        except (ValueError, json.JSONDecodeError):
            # If not JSON, treat as a simple string parameter
            backend_params["config"] = backend_config

    # Extract any additional backend-specific parameters
    # Look for arguments that start with "backend_"
    for attr_name in dir(args):
        if attr_name.startswith('backend_') and attr_name not in ['backend_host', 'backend_port', 'backend_config']:
            value = getattr(args, attr_name, None)
            if value is not None:
                param_name = attr_name[8:]  # Remove 'backend_' prefix
                backend_params[param_name] = value

    return backend_params if backend_params else None

